# 输入获取
n = int(input())

relations = []
while True:
    line = input()

    # 本题没有给输入终止条件,因此我已输入空串为结束条件
    if "" == line:
        break

    relations.append(list(map(int, line.split())))


# 算法入口
def getResult():
    inDegree = [0] * n
    next = {}

    for a, b in relations:
        inDegree[b] += 1
        next.setdefault(a, [])
        next[a].append(b)

    stack = []
    for i in range(n):
        if inDegree[i] == 0:
            stack.append(i)

    count = 0
    while len(stack) > 0:
        a = stack.pop()
        count += 1

        if next.get(a) is not None:
            for b in next[a]:
                inDegree[b] -= 1
                if inDegree[b] == 0:
                    stack.append(b)

    return "yes" if count == n else "no"


# 算法调用
print(getResult())
